import{_ as t,o as s,c as a,a2 as n}from"./chunks/framework.CsxL8ROK.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),i={name:"architecture.md"};function o(d,e,r,c,l,p){return s(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="request-flow" tabindex="-1">Request flow <a class="header-anchor" href="#request-flow" aria-label="Permalink to &quot;Request flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub event</span></span>
<span class="line"><span>  → POST /api/github/webhook</span></span>
<span class="line"><span>  → signature verification (HMAC-SHA256)</span></span>
<span class="line"><span>  → octokit webhook dispatch</span></span>
<span class="line"><span>  → issue_comment.created handler</span></span>
<span class="line"><span>    → parse /codex-review command</span></span>
<span class="line"><span>    → trust check (author association)</span></span>
<span class="line"><span>    → GET /pulls/{number} (fetch PR metadata)</span></span>
<span class="line"><span>    → GET /pulls/{number}/files (fetch diffs)</span></span>
<span class="line"><span>    → build prompt (skill + custom prompt + diffs)</span></span>
<span class="line"><span>    → OpenAI Responses API (structured JSON output)</span></span>
<span class="line"><span>    → validate inline comment anchors against diff</span></span>
<span class="line"><span>    → POST /pulls/{number}/reviews</span></span>
<span class="line"><span>  → 202 Accepted</span></span></code></pre></div><h2 id="key-files" tabindex="-1">Key files <a class="header-anchor" href="#key-files" aria-label="Permalink to &quot;Key files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>api/github/webhook.ts</code></td><td>Vercel entrypoint: reads raw body, verifies signature, dispatches event</td></tr><tr><td><code>src/github-app.ts</code></td><td>Registers webhook event handlers, manages the Octokit <code>App</code> singleton</td></tr><tr><td><code>src/review.ts</code></td><td>Fetches diff, calls OpenAI, validates anchors, builds <code>ReviewDecision</code></td></tr><tr><td><code>src/prompt.ts</code></td><td>Assembles the full prompt from skill file + metadata + diffs</td></tr><tr><td><code>src/commands.ts</code></td><td>Parses <code>/codex-review</code> command body, extracts flags and extra instructions</td></tr><tr><td><code>src/config.ts</code></td><td>Reads and validates all environment variables at startup</td></tr><tr><td><code>src/openai.ts</code></td><td>Creates and caches the OpenAI client singleton</td></tr><tr><td><code>skills/code-review-excellence/SKILL.md</code></td><td>Vendored review policy loaded into every prompt</td></tr></tbody></table><h2 id="anchor-validation" tabindex="-1">Anchor validation <a class="header-anchor" href="#anchor-validation" aria-label="Permalink to &quot;Anchor validation&quot;">​</a></h2><p>The OpenAI model returns inline comments with <code>path</code>, <code>line</code>, and optional <code>start_line</code>. Before submitting:</p><ol><li>The bot builds a set of valid right-side line numbers for each file from the raw diff</li><li>Any comment whose <code>line</code> is not in that set is dropped</li><li>Any comment whose <code>start_line &gt;= line</code> (backwards range) is dropped</li><li>Any comment whose <code>start_line</code> is not in the valid set is dropped</li></ol><p>This prevents the model from hallucinating line numbers that don&#39;t exist in the diff.</p><h2 id="webhook-response-timing" tabindex="-1">Webhook response timing <a class="header-anchor" href="#webhook-response-timing" aria-label="Permalink to &quot;Webhook response timing&quot;">​</a></h2><p>The handler calls <code>app.webhooks.verifyAndReceive()</code> — which awaits all registered handlers — before sending <code>202 Accepted</code>. This means the Vercel function stays alive during the OpenAI API call (typically 5–20 seconds). GitHub&#39;s webhook timeout is 10 seconds; GitHub will mark the delivery as timed out but the review still posts successfully.</p><div class="tip custom-block"><p class="custom-block-title">Improving latency</p><p>To respond 202 immediately and process in the background, move the review logic into a queued job (e.g. Vercel Queues or a background function). This is a known improvement opportunity.</p></div><h2 id="structured-output-schema" tabindex="-1">Structured output schema <a class="header-anchor" href="#structured-output-schema" aria-label="Permalink to &quot;Structured output schema&quot;">​</a></h2><p>The bot uses OpenAI&#39;s Responses API with <code>strict: true</code> JSON schema. All properties declared in <code>properties</code> must appear in <code>required</code>. Optional fields use <code>[&quot;type&quot;, &quot;null&quot;]</code> instead of being omitted from <code>required</code>.</p>`,14)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
